    inline void Predict(const Model& model, const float input[N_INPUTS], float output[3])
    {
        for (int i = 0; i < 3; i++) {
            float sum = model.bias[i];
            for (int j = 0; j < N_INPUTS; j++)
                sum += model.weights[i][j] * input[j];
            output[i] = std::clamp(sum, 0.0f, 1.0f);
        }
    }

